import React, { useState, useRef } from 'react';
import axios from 'axios';
import toast from 'react-hot-toast';
import { Code2, Upload, Download, FileSpreadsheet, Copy, Sparkles } from 'lucide-react';

const API = 'http://localhost:8000/api';

export default function AutomationGenerator() {
  const [testCases, setTestCases] = useState([]);
  const [framework, setFramework] = useState('playwright');
  const [script, setScript] = useState('');
  const [loading, setLoading] = useState(false);
  const [dragOver, setDragOver] = useState(false);
  const fileRef = useRef();

  const handleUpload = async (file) => {
    if (!file) return;

    // Read file as binary and send directly to backend
    const formData = new FormData();
    formData.append('file', file);

    try {
      const res = await axios.post(`${API}/testcases/upload`, formData, {
        headers: { 'Content-Type': 'multipart/form-data' },
      });

      // Normalize each test case — handle any column name variant
      const normalized = res.data.test_cases.map((tc, i) => ({
        id:       tc.id || tc.ID || tc['test id'] || tc['TC ID'] || `TC_${String(i+1).padStart(3,'0')}`,
        title:    tc.title || tc.Title || tc['test title'] || tc['Test Title'] || tc['test case title'] || tc['Test Case Title'] || tc.name || tc.Name || '',
        steps:    tc.steps || tc.Steps || tc['test steps'] || tc['Test Steps'] || tc.actions || tc.Actions || '',
        expected: tc.expected || tc.Expected || tc['expected result'] || tc['Expected Result'] || tc['expected results'] || tc['Expected Results'] || tc.result || tc.Result || tc.outcome || tc.Outcome || '',
        type:     tc.type || tc.Type || 'positive',
        priority: tc.priority || tc.Priority || 'Medium',
      }));

      setTestCases(normalized);
      toast.success(`${normalized.length} test cases loaded`);
    } catch (e) {
      toast.error(e.response?.data?.detail || 'Upload failed');
    }
  };

  const generate = async () => {
    if (!testCases.length) { toast.error('Upload test cases first'); return; }
    setLoading(true);
    setScript('');
    try {
      if (framework === 'both') {
        const res = await axios.post(
          `${API}/automation/generate`,
          { test_cases: testCases, framework: 'both' },
          { responseType: 'blob' }
        );
        const url = window.URL.createObjectURL(res.data);
        const a = document.createElement('a');
        a.href = url; a.download = 'automation_scripts.zip'; a.click();
        toast.success('ZIP downloaded!');
      } else {
        const res = await axios.post(`${API}/automation/generate`, {
          test_cases: testCases,
          framework,
        });
        setScript(res.data.script);
        toast.success('Script generated!');
      }
    } catch (e) {
      toast.error(e.response?.data?.detail || 'Generation failed');
    } finally {
      setLoading(false);
    }
  };

  const downloadScript = () => {
    const ext = framework === 'playwright' ? 'spec.js' : 'test.js';
    const blob = new Blob([script], { type: 'text/javascript' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url; a.download = `generated.${ext}`; a.click();
    toast.success('Downloaded!');
  };

  const frameworks = [
    { id: 'playwright', label: 'Playwright JS', desc: 'Modern, fast, reliable' },
    { id: 'selenium',   label: 'Selenium JS',   desc: 'WebdriverIO based' },
    { id: 'both',       label: 'Both',           desc: 'Download as ZIP' },
  ];

  return (
    <div>
      <div style={{ marginBottom: 24 }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 4 }}>
          <Code2 size={20} color="#0284c7" />
          <h1>Automation Script Generator</h1>
        </div>
        <p className="page-subtitle">Convert your test cases into ready-to-run automation scripts.</p>
      </div>

      {/* Step 1 */}
      <div className="card">
        <h2 style={{ marginBottom: 12 }}>Step 1 — Upload Test Cases</h2>
        <div
          className={`upload-zone ${dragOver ? 'active' : ''}`}
          onClick={() => fileRef.current.click()}
          onDragOver={e => { e.preventDefault(); setDragOver(true); }}
          onDragLeave={() => setDragOver(false)}
          onDrop={e => { e.preventDefault(); setDragOver(false); handleUpload(e.dataTransfer.files[0]); }}
        >
          <FileSpreadsheet size={28} color="#1a56db" style={{ opacity: 0.6 }} />
          <p><strong>Click to upload</strong> or drag & drop</p>
          <p>Supports .xlsx and .csv</p>
          <p style={{ fontSize: 11, color: '#94a3b8', marginTop: 6 }}>
            Accepted columns: ID, Title, Type, Steps, Expected Result, Priority
          </p>
        </div>
        <input
          ref={fileRef}
          type="file"
          accept=".xlsx,.csv"
          style={{ display: 'none' }}
          onChange={e => handleUpload(e.target.files[0])}
        />
        {testCases.length > 0 && (
          <div style={{ marginTop: 12, padding: '10px 14px', background: '#e0f2fe', borderRadius: 8, display: 'flex', alignItems: 'center', gap: 8 }}>
            <Upload size={14} color="#0284c7" />
            <span style={{ fontSize: 13, color: '#0c4a6e', fontWeight: 500 }}>
              {testCases.length} test cases loaded — ready to generate
            </span>
          </div>
        )}

        {/* Preview table */}
        {testCases.length > 0 && (
          <div style={{ marginTop: 14, overflowX: 'auto' }}>
            <table className="tc-table">
              <thead>
                <tr>
                  <th>ID</th><th>Title</th><th>Steps</th><th>Expected</th><th>Priority</th>
                </tr>
              </thead>
              <tbody>
                {testCases.slice(0, 3).map((tc, i) => (
                  <tr key={i}>
                    <td><code style={{ fontSize: 11, color: '#1a56db' }}>{tc.id}</code></td>
                    <td style={{ maxWidth: 160, fontSize: 12 }}>{tc.title}</td>
                    <td style={{ maxWidth: 200, fontSize: 11, color: '#555' }}>{String(tc.steps).substring(0, 60)}...</td>
                    <td style={{ maxWidth: 160, fontSize: 11 }}>{String(tc.expected).substring(0, 60)}</td>
                    <td><span className={`badge badge-${(tc.priority||'').toLowerCase()}`}>{tc.priority}</span></td>
                  </tr>
                ))}
              </tbody>
            </table>
            {testCases.length > 3 && (
              <div style={{ fontSize: 11, color: '#94a3b8', padding: '6px 12px' }}>
                + {testCases.length - 3} more test cases
              </div>
            )}
          </div>
        )}
      </div>

      {/* Step 2 */}
      <div className="card">
        <h2 style={{ marginBottom: 12 }}>Step 2 — Select Framework</h2>
        <div className="framework-grid">
          {frameworks.map(f => (
            <div
              key={f.id}
              className={`framework-option ${framework === f.id ? 'selected' : ''}`}
              onClick={() => setFramework(f.id)}
            >
              <div style={{ fontWeight: 600, marginBottom: 4 }}>{f.label}</div>
              <div style={{ fontSize: 11, color: framework === f.id ? '#1a56db' : '#888' }}>{f.desc}</div>
            </div>
          ))}
        </div>
      </div>

      {/* Step 3 */}
      <div className="card">
        <h2 style={{ marginBottom: 4 }}>Step 3 — Generate Script</h2>
        <p style={{ fontSize: 13, color: '#666', marginBottom: 16 }}>
          {framework === 'both'
            ? 'Both Playwright and Selenium scripts will be packaged into a ZIP.'
            : `A ${framework === 'playwright' ? 'Playwright' : 'Selenium (WebdriverIO)'} JavaScript test file will be generated.`}
        </p>
        <button className="btn btn-teal" onClick={generate} disabled={loading}>
          {loading
            ? <><div className="spinner" />Generating…</>
            : <><Sparkles size={15} />Generate {framework === 'both' ? 'Both Scripts' : `${framework.charAt(0).toUpperCase() + framework.slice(1)} Script`}</>
          }
        </button>
      </div>

      {/* Script output */}
      {script && (
        <div className="card" style={{ padding: 0, overflow: 'hidden' }}>
          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '14px 20px', borderBottom: '1px solid #f0eff8' }}>
            <div>
              <h2 style={{ margin: 0 }}>Generated Script</h2>
              <div style={{ fontSize: 11, color: '#888', marginTop: 2 }}>
                {framework === 'playwright' ? 'Playwright · generated.spec.js' : 'Selenium WebdriverIO · generated.test.js'}
              </div>
            </div>
            <div style={{ display: 'flex', gap: 8 }}>
              <button className="btn btn-secondary btn-sm" onClick={() => { navigator.clipboard.writeText(script); toast.success('Copied!'); }}>
                <Copy size={13} /> Copy
              </button>
              <button className="btn btn-teal btn-sm" onClick={downloadScript}>
                <Download size={13} /> Download
              </button>
            </div>
          </div>
          <div className="code-block" style={{ borderRadius: 0 }}>{script}</div>
        </div>
      )}
    </div>
  );
}
